    scwin.hid_cntrDsgYn = "" + scwin.YN_NO;
    scwin.hid_transCargoClsCd = scwin.ODR_BULK;
    scwin.hid_impExpDomesticClsCd = "";

    scwin.hid_odrClsCd = "" + scwin.YN_NO;
